import{_ as t,c as r,m as a,a as o,t as i,a5 as n,o as l}from"./chunks/framework.DwbewbAn.js";const k=JSON.parse('{"title":"@Transcation注解事务不生效场景","description":"","frontmatter":{"title":"@Transcation注解事务不生效场景"},"headers":[],"relativePath":"doc/编程语言/后端/Java/框架/Spring/Transcation注解事务不生效场景.md","filePath":"packages/doc/src/编程语言/后端/Java/框架/Spring/Transcation注解事务不生效场景.md","lastUpdated":1711551906000}'),c={name:"doc/编程语言/后端/Java/框架/Spring/Transcation注解事务不生效场景.md"},s={id:"frontmatter-title",tabindex:"-1"},h=a("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),d=n('<h2 id="数据库引擎不支持事务" tabindex="-1">数据库引擎不支持事务 <a class="header-anchor" href="#数据库引擎不支持事务" aria-label="Permalink to &quot;数据库引擎不支持事务&quot;">​</a></h2><p>mysql的ISAM不支持事务</p><h2 id="注解的类是非public修饰的方法上" tabindex="-1">注解的类是非public修饰的方法上， <a class="header-anchor" href="#注解的类是非public修饰的方法上" aria-label="Permalink to &quot;注解的类是非public修饰的方法上，&quot;">​</a></h2><p>底层使用了动态代理，并规定了访问权限是public</p><h2 id="注解的方法被标注为final类型" tabindex="-1">注解的方法被标注为final类型 <a class="header-anchor" href="#注解的方法被标注为final类型" aria-label="Permalink to &quot;注解的方法被标注为final类型&quot;">​</a></h2><p>由于底层使用了动态代理，如果设置为final就表示不能生成动态代理对象</p><h2 id="注解的属性rollbackfor设置错误" tabindex="-1">注解的属性rollbackFor设置错误， <a class="header-anchor" href="#注解的属性rollbackfor设置错误" aria-label="Permalink to &quot;注解的属性rollbackFor设置错误，&quot;">​</a></h2><p>默认是RuntimeException以及子类，如果需要支持其他异常需要指明在rollbackFor属性内</p><h2 id="注解的属性propagation设置错误" tabindex="-1">注解的属性propagation设置错误： <a class="header-anchor" href="#注解的属性propagation设置错误" aria-label="Permalink to &quot;注解的属性propagation设置错误：&quot;">​</a></h2><p>默认是REQUIRE，如果设置为NOT_SUPPORT，会因为有事务抛出异常，如果是MANDATORY 则会因为外层没有事务的话导致报错</p><h2 id="注解的方法内异常被手动捕获" tabindex="-1">注解的方法内异常被手动捕获 <a class="header-anchor" href="#注解的方法内异常被手动捕获" aria-label="Permalink to &quot;注解的方法内异常被手动捕获&quot;">​</a></h2><p>底层是方法根据抛出的异常决定是否回滚，如果被捕获了，没有抛出，外层自然拿不到异常</p><h2 id="同一个方法内自调用-导致失效" tabindex="-1">同一个方法内自调用，导致失效 <a class="header-anchor" href="#同一个方法内自调用-导致失效" aria-label="Permalink to &quot;同一个方法内自调用，导致失效&quot;">​</a></h2><h2 id="注解的方法所属的类没有被spring管理" tabindex="-1">注解的方法所属的类没有被spring管理 <a class="header-anchor" href="#注解的方法所属的类没有被spring管理" aria-label="Permalink to &quot;注解的方法所属的类没有被spring管理&quot;">​</a></h2><p>比如所在类没有使用@Controller,@Service,@Componment，@Bean等注解</p><h2 id="注解的方法内部采用了多线程调用" tabindex="-1">注解的方法内部采用了多线程调用 <a class="header-anchor" href="#注解的方法内部采用了多线程调用" aria-label="Permalink to &quot;注解的方法内部采用了多线程调用&quot;">​</a></h2><p>根据事务底层原理，即子线程的状态，主流程线程不能影响到</p><h2 id="嵌套事务导致回滚失效" tabindex="-1">嵌套事务导致回滚失效 <a class="header-anchor" href="#嵌套事务导致回滚失效" aria-label="Permalink to &quot;嵌套事务导致回滚失效&quot;">​</a></h2><p>根据嵌套事务定义，内存事务回滚不会导致外层事务回滚，外层事务回滚，内存事务也会回滚</p>',19);function p(e,_,b,u,f,m){return l(),r("div",null,[a("h1",s,[o(i(e.$frontmatter.title)+" ",1),h]),d])}const P=t(c,[["render",p]]);export{k as __pageData,P as default};
